        [HttpPost("/orders")]
        public async Task&lt;IActionResult&gt; CreateOrder([FromBody] CreateOrderRequest request)
        {
            using var activity = ActivitySource.StartActivity("CreateOrder");
            activity?.SetTag("order.customer_id", request.CustomerId);

